// Detect the beacio Safari Web Extension on iPhone at runtime.
// Standard surface: navigator.bluetooth (present on every browser with beacio or native support).
// Premium surface: window.beacioIOS (present only on iPhone + beacio companion app).
const hasStandardBluetooth = typeof navigator !== 'undefined' && 'bluetooth' in navigator;
const hasPremiumIOS = typeof window !== 'undefined' && 'beacioIOS' in window;

if (hasStandardBluetooth) {
  const available = await navigator.bluetooth.getAvailability();
  console.log('navigator.bluetooth available:', available);
}

if (hasPremiumIOS) {
  const caps = await window.beacioIOS.getCapabilities();
  console.log('beacio iOS capabilities:', caps);
} else {
  // Standard surface only — peripheral mode, background sync, beacons, and notifications are unavailable.
}
